  import sailpoint.rapidapponboarding.rule.LeaverRuleLibrary;
  // THIS  IS THE ENTRY POINT METHOD THAT IDENTITY TRIGGER CALLS WHEN INVOKED BY THE IDENTITY REFRESH
  import sailpoint.object.Custom;
  import java.text.SimpleDateFormat;
  import java.util.Calendar;
  import java.util.Date;
  import java.util.GregorianCalendar;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Identity;
  import sailpoint.tools.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  static Log logger = LogFactory.getLog("rule.Rule.IdentityTrigger.Leaver");
  logger.info("Rule.IdentityTrigger.Leaver Start ");
  boolean status = false;
  String expiredDate = null;	  	
  String userType = null;
  String hotTerm = null;
  String inputDateFormat = null; 

  if(null != newIdentity){
    expiredDate = newIdentity.getAttribute("ctrexpDt");	  	
    userType = newIdentity.getAttribute("type"); 
    hotTerm = newIdentity.getAttribute("manualTerm"); 
  }


  Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
  List contractorTypes = new ArrayList();
  if(custom!=null && custom.get("ContractorType") !=null){
    contractorTypes = custom.get("ContractorType");
    inputDateFormat = custom.get("DateFormat");	
    //comment decache //context.decache(custom);
  }

  if(null != contractorTypes && contractorTypes.contains(userType)){ 
    if(null != newIdentity && !newIdentity.isInactive() && !(Util.isNotNullOrEmpty(hotTerm) && hotTerm.equalsIgnoreCase("yes")) && Util.isNotNullOrEmpty(inputDateFormat) && Util.isNotNullOrEmpty(expiredDate)){
      SimpleDateFormat dateFormat = new SimpleDateFormat(inputDateFormat);
      try{
        Date lastDay= dateFormat.parse(expiredDate);           
        Calendar calendar = GregorianCalendar.getInstance(); 
        calendar.setTime(lastDay);
        calendar.set(GregorianCalendar.HOUR,0);
        calendar.set(GregorianCalendar.MINUTE,0);
        calendar.set(GregorianCalendar.SECOND,0);
        calendar.set(GregorianCalendar.MILLISECOND ,0);
        calendar.set(GregorianCalendar.HOUR_OF_DAY,0);
        calendar.add(Calendar.DAY_OF_MONTH, +1);
        Date expDatePlusOne = calendar.getTime();

        Date currentDate = new Date();
        Calendar today = GregorianCalendar.getInstance(); 
        today.setTime(currentDate);
        today.set(GregorianCalendar.HOUR,0);
        today.set(GregorianCalendar.MINUTE,0);
        today.set(GregorianCalendar.SECOND,0);
        today.set(GregorianCalendar.MILLISECOND ,0);
        today.set(GregorianCalendar.HOUR_OF_DAY,0);
        Date todayDate = today.getTime();

        if(null != expDatePlusOne && null != todayDate && expDatePlusOne.equals(todayDate) || expDatePlusOne.before(todayDate)){     
          status =  true;       
        }
        else{
          status = false;
        }        
      }
      catch(Exception e){
        logger.error("Exception Message "+e);
      }
    }
    logger.info("Rule.IdentityTrigger.Leaver End ");
    return status;
  }  else{
    return LeaverRuleLibrary.isEligibleForLeaver(context, previousIdentity, newIdentity);
  }
